using System;
using System.Diagnostics;

public class PdfGenerator
{
    public void GeneratePdf(string htmlFilePath, string pdfFilePath, string pageSize = "Letter", string orientation = "Portrait")
    {
        if (string.IsNullOrEmpty(htmlFilePath) || !System.IO.File.Exists(htmlFilePath))
        {
            throw new ArgumentException("HTML file path is invalid or does not exist.");
        }

        if (string.IsNullOrEmpty(pdfFilePath))
        {
            throw new ArgumentException("PDF file path cannot be empty.");
        }

        string wkhtmltopdfPath = "wkhtmltopdf"; // Ensure this path is correct or provide a full path
        string arguments = $"\"{htmlFilePath}\" \"{pdfFilePath}\" --page-size {pageSize} --orientation {orientation}";

        ProcessStartInfo startInfo = new ProcessStartInfo
        {
            FileName = wkhtmltopdfPath,
            Arguments = arguments,
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            UseShellExecute = false,
            CreateNoWindow = true
        };

        using (Process process = new Process { StartInfo = startInfo })
        {
            process.Start();
            string output = process.StandardOutput.ReadToEnd();
            string error = process.StandardError.ReadToEnd();
            process.WaitForExit();

            if (!string.IsNullOrEmpty(error))
            {
                throw new Exception($"wkhtmltopdf encountered an error: {error}");
            }

            Console.WriteLine(output);
        }
    }
}